// RunMonorepo discovers and runs all sub-configs in a monorepo.
func (r *Runner) RunMonorepo(opts RunOptions, subConfigs []monorepo.SubConfig) (*SuiteResult, error) {
	start := time.Now()

	suite := &SuiteResult{
		Project: r.Config.Project,
	}

	for _, sc := range subConfigs {
