1	package reporter
2	
3	import (
4		"fmt"
5		"io"
6		"strings"
7		"time"
8	
9		"github.com/charmbracelet/lipgloss"
10	)
11	
12	var (
13		passStyle  = lipgloss.NewStyle().Foreground(lipgloss.Color("2"))  // green
14		failStyle  = lipgloss.NewStyle().Foreground(lipgloss.Color("1"))  // red
15		skipStyle  = lipgloss.NewStyle().Foreground(lipgloss.Color("3"))  // yellow
16		dimStyle   = lipgloss.NewStyle().Foreground(lipgloss.Color("8"))  // gray
17		boldStyle  = lipgloss.NewStyle().Bold(true)
18		labelStyle = lipgloss.NewStyle().Foreground(lipgloss.Color("6"))  // cyan
19	)
20	
21	// Terminal writes colored test output to a writer.
22	type Terminal struct {
23		w io.Writer
24	}
25	
26	// NewTerminal creates a terminal reporter writing to w.
27	func NewTerminal(w io.Writer) *Terminal {
28		return &Terminal{w: w}
29	}
30	
31	func (t *Terminal) PrereqStart(name string) {
32		fmt.Fprintf(t.w, "  %s %s", dimStyle.Render("●"), name)
33	}
34	
35	func (t *Terminal) PrereqResult(r PrereqResultData) {
36		if r.Passed {
37			out := ""
38			if r.Output != "" {
39				out = dimStyle.Render(" (" + r.Output + ")")
40			}
41			fmt.Fprintf(t.w, "\r  %s %s%s\n", passStyle.Render("✓"), r.Name, out)
42		} else {
43			fmt.Fprintf(t.w, "\r  %s %s\n", failStyle.Render("✗"), r.Name)
44			if r.Hint != "" {
45				fmt.Fprintf(t.w, "    %s %s\n", labelStyle.Render("hint:"), r.Hint)
46			}
47		}
48	}
49	
50	func (t *Terminal) TestStart(name string) {
51		fmt.Fprintf(t.w, "  %s %s", dimStyle.Render("●"), name)
52	}
53	
54	func (t *Terminal) TestResult(r TestResultData) {
55		dur := formatDuration(r.Duration)
56	
57		if r.Skipped {
58			fmt.Fprintf(t.w, "\r  %s %s %s\n", skipStyle.Render("⊘"), r.Name, dimStyle.Render(dur))
59			return
60		}
61	
62		if r.Passed {
63			fmt.Fprintf(t.w, "\r  %s %s %s\n", passStyle.Render("✓"), r.Name, dimStyle.Render(dur))
64		} else if r.AllowedFailure {
65			fmt.Fprintf(t.w, "\r  %s %s %s\n", skipStyle.Render("~"), r.Name, dimStyle.Render(dur+" allowed"))
66			for _, a := range r.Assertions {
67				if !a.Passed {
68					fmt.Fprintf(t.w, "    %s expected %s, got %s\n",
69						skipStyle.Render(a.Type+":"),
70						a.Expected,
71						a.Actual)
72				}
73			}
74			if r.Error != nil {
75				fmt.Fprintf(t.w, "    %s %s\n", skipStyle.Render("error:"), r.Error)
